-- ============================================================
-- ProfiClub CRM — Supabase SQL Setup
-- Supabase SQL Editor ga nusxalab, Run bosing
-- ============================================================

-- 1. JADVALLAP YARATISH
-- ============================================================

CREATE TABLE IF NOT EXISTS employees (
  id           BIGSERIAL PRIMARY KEY,
  name         TEXT NOT NULL,
  role         TEXT NOT NULL,
  data         JSONB DEFAULT '{}',
  exam_results JSONB DEFAULT '[]',
  created_at   TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS trainings (
  id         TEXT PRIMARY KEY,
  title      TEXT NOT NULL,
  date       TEXT,
  questions  JSONB DEFAULT '[]',
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 2. RLS (Row Level Security) — hamma o'qiy va yoza olsin
-- ============================================================

ALTER TABLE employees ENABLE ROW LEVEL SECURITY;
ALTER TABLE trainings ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all on employees" ON employees FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow all on trainings" ON trainings FOR ALL USING (true) WITH CHECK (true);

